"use client";

import { useRef } from "react";
import { motion, useScroll, useTransform } from "framer-motion";
import Link from "next/link";
import { ArrowUpRight, Brain, Cpu, TrendingUp, Cloud, Database, Palette } from "lucide-react";

const services = [
    {
        icon: Brain,
        title: "AI Strategy",
        description: "Intelligent systems that learn, adapt, and transform your business operations.",
        color: "#00F0FF",
        features: ["Machine Learning", "NLP Solutions", "Predictive Analytics"],
        slug: "ai-strategy",
    },
    {
        icon: Cpu,
        title: "Digital Engineering",
        description: "End-to-end digital transformation with cutting-edge technologies and methodologies.",
        color: "#FF00FF",
        features: ["System Architecture", "API Development", "Microservices"],
        slug: "digital-engineering",
    },
    {
        icon: TrendingUp,
        title: "Growth Systems",
        description: "Data-driven growth engines that scale with your ambition and market demands.",
        color: "#8B5CF6",
        features: ["Growth Hacking", "CRO", "Marketing Automation"],
        slug: "growth-systems",
    },
    {
        icon: Cloud,
        title: "Cloud Architecture",
        description: "Scalable, resilient infrastructure for the modern enterprise ecosystem.",
        color: "#14B8A6",
        features: ["AWS/Azure/GCP", "DevOps", "Serverless"],
        slug: "cloud-architecture",
    },
    {
        icon: Database,
        title: "Data Intelligence",
        description: "Transform raw data into actionable insights that drive strategic decisions.",
        color: "#F59E0B",
        features: ["Data Engineering", "BI Solutions", "Data Visualization"],
        slug: "data-intelligence",
    },
    {
        icon: Palette,
        title: "Product Design",
        description: "User-centered design that combines aesthetics with functionality and purpose.",
        color: "#EC4899",
        features: ["UX Research", "UI Design", "Design Systems"],
        slug: "product-design",
    },
];

export default function ServicesSection() {
    const sectionRef = useRef<HTMLDivElement>(null);
    const { scrollYProgress } = useScroll({
        target: sectionRef,
        offset: ["start end", "end start"],
    });

    const y = useTransform(scrollYProgress, [0, 1], [100, -100]);

    return (
        <section
            ref={sectionRef}
            className="relative min-h-screen py-32 overflow-hidden"
        >
            {/* Background */}
            <div className="absolute inset-0 bg-gradient-to-b from-[#050A14] via-[#0A1428] to-[#050A14]" />

            {/* Floating Elements */}
            <motion.div
                style={{ y }}
                className="absolute inset-0 pointer-events-none"
            >
                <div className="absolute top-1/4 right-0 w-96 h-96 bg-[#00F0FF]/10 rounded-full blur-3xl" />
                <div className="absolute bottom-1/4 left-0 w-96 h-96 bg-[#FF00FF]/10 rounded-full blur-3xl" />
            </motion.div>

            <div className="relative z-10 container-custom">
                {/* Section Header */}
                <div className="flex flex-col md:flex-row md:items-end md:justify-between mb-16">
                    <div>
                        <motion.span
                            initial={{ opacity: 0, y: 20 }}
                            whileInView={{ opacity: 1, y: 0 }}
                            viewport={{ once: true }}
                            className="inline-block px-4 py-2 rounded-full glass text-[#FF00FF] text-sm font-medium mb-6"
                        >
                            What We Do
                        </motion.span>
                        <motion.h2
                            initial={{ opacity: 0, y: 30 }}
                            whileInView={{ opacity: 1, y: 0 }}
                            viewport={{ once: true }}
                            transition={{ delay: 0.1 }}
                            className="text-4xl sm:text-5xl md:text-6xl font-bold"
                        >
                            Our <span className="text-gradient">Services</span>
                        </motion.h2>
                    </div>
                    <motion.p
                        initial={{ opacity: 0, y: 30 }}
                        whileInView={{ opacity: 1, y: 0 }}
                        viewport={{ once: true }}
                        transition={{ delay: 0.2 }}
                        className="text-white/60 max-w-md mt-6 md:mt-0"
                    >
                        Comprehensive digital solutions tailored to accelerate your business
                        growth and technological advancement.
                    </motion.p>
                </div>

                {/* Services Grid */}
                <div className="grid md:grid-cols-2 lg:grid-cols-3 gap-6">
                    {services.map((service, index) => (
                        <Link key={service.slug} href={`/services/${service.slug}`}>
                            <motion.div
                                initial={{ opacity: 0, y: 40 }}
                                whileInView={{ opacity: 1, y: 0 }}
                                viewport={{ once: true }}
                                transition={{ delay: index * 0.1 }}
                                className="group relative h-full"
                            >
                                <div className="relative h-full p-8 rounded-2xl glass hover:bg-white/5 transition-all duration-500 overflow-hidden">
                                    {/* Hover Gradient */}
                                    <div
                                        className="absolute inset-0 opacity-0 group-hover:opacity-100 transition-opacity duration-500"
                                        style={{
                                            background: `radial-gradient(circle at 50% 0%, ${service.color}15 0%, transparent 70%)`,
                                        }}
                                    />

                                    {/* Top Border Glow */}
                                    <div
                                        className="absolute top-0 left-0 right-0 h-px opacity-0 group-hover:opacity-100 transition-opacity duration-500"
                                        style={{
                                            background: `linear-gradient(90deg, transparent, ${service.color}, transparent)`,
                                        }}
                                    />

                                    <div className="relative z-10">
                                        {/* Icon & Arrow */}
                                        <div className="flex items-start justify-between mb-6">
                                            <div
                                                className="w-12 h-12 rounded-xl flex items-center justify-center transition-transform duration-300 group-hover:scale-110"
                                                style={{ backgroundColor: `${service.color}15` }}
                                            >
                                                <service.icon
                                                    className="w-6 h-6"
                                                    style={{ color: service.color }}
                                                />
                                            </div>
                                            <motion.div
                                                className="w-10 h-10 rounded-full border border-white/10 flex items-center justify-center group-hover:border-white/30 transition-colors"
                                                whileHover={{ scale: 1.1 }}
                                            >
                                                <ArrowUpRight className="w-4 h-4 text-white/50 group-hover:text-white transition-colors" />
                                            </motion.div>
                                        </div>

                                        {/* Content */}
                                        <h3 className="text-xl font-bold mb-3 group-hover:text-white transition-colors">
                                            {service.title}
                                        </h3>
                                        <p className="text-white/60 mb-6 text-sm leading-relaxed">
                                            {service.description}
                                        </p>

                                        {/* Features */}
                                        <div className="flex flex-wrap gap-2">
                                            {service.features.map((feature) => (
                                                <span
                                                    key={feature}
                                                    className="px-3 py-1 rounded-full text-xs font-medium bg-white/5 text-white/70"
                                                >
                                                    {feature}
                                                </span>
                                            ))}
                                        </div>
                                    </div>

                                    {/* Number */}
                                    <div
                                        className="absolute -bottom-4 -right-4 text-8xl font-bold opacity-5 group-hover:opacity-10 transition-opacity"
                                        style={{ color: service.color }}
                                    >
                                        0{index + 1}
                                    </div>
                                </div>
                            </motion.div>
                        </Link>
                    ))}
                </div>

                {/* View All Button */}
                <motion.div
                    initial={{ opacity: 0, y: 30 }}
                    whileInView={{ opacity: 1, y: 0 }}
                    viewport={{ once: true }}
                    className="flex justify-center mt-12"
                >
                    <Link href="/services">
                        <motion.button
                            className="px-8 py-4 border border-white/20 rounded-full font-medium hover:border-[#00F0FF]/50 hover:bg-[#00F0FF]/10 transition-all duration-300 flex items-center gap-2 group"
                            whileHover={{ scale: 1.05 }}
                            whileTap={{ scale: 0.95 }}
                        >
                            View All Services
                            <ArrowUpRight className="w-4 h-4 group-hover:translate-x-0.5 group-hover:-translate-y-0.5 transition-transform" />
                        </motion.button>
                    </Link>
                </motion.div>
            </div>
        </section>
    );
}
