"use client";

import { useRef } from "react";
import { motion, useScroll, useTransform } from "framer-motion";
import Link from "next/link";
import { ArrowRight, Sparkles } from "lucide-react";

export default function CTASection() {
    const sectionRef = useRef<HTMLDivElement>(null);
    const { scrollYProgress } = useScroll({
        target: sectionRef,
        offset: ["start end", "end start"],
    });

    const y = useTransform(scrollYProgress, [0, 1], [100, -100]);
    const scale = useTransform(scrollYProgress, [0, 0.5, 1], [0.8, 1, 0.8]);
    const opacity = useTransform(scrollYProgress, [0, 0.2, 0.8, 1], [0, 1, 1, 0]);

    return (
        <section
            ref={sectionRef}
            className="relative min-h-screen flex items-center justify-center py-32 overflow-hidden"
        >
            {/* Background Effects */}
            <div className="absolute inset-0">
                {/* Animated gradient orbs */}
                <motion.div
                    style={{ y }}
                    className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 w-[800px] h-[800px]"
                >
                    <div
                        className="absolute inset-0 rounded-full animate-pulse"
                        style={{
                            background: "radial-gradient(circle, rgba(0, 240, 255, 0.3) 0%, transparent 60%)",
                            filter: "blur(100px)",
                        }}
                    />
                </motion.div>

                <motion.div
                    animate={{
                        scale: [1, 1.2, 1],
                        opacity: [0.3, 0.5, 0.3],
                    }}
                    transition={{
                        duration: 4,
                        repeat: Infinity,
                        ease: "easeInOut",
                    }}
                    className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 w-[600px] h-[600px]"
                >
                    <div
                        className="absolute inset-0 rounded-full"
                        style={{
                            background: "radial-gradient(circle, rgba(255, 0, 255, 0.2) 0%, transparent 60%)",
                            filter: "blur(80px)",
                        }}
                    />
                </motion.div>

                {/* Grid pattern */}
                <div
                    className="absolute inset-0 opacity-10"
                    style={{
                        backgroundImage: `
              linear-gradient(rgba(0, 240, 255, 0.5) 1px, transparent 1px),
              linear-gradient(90deg, rgba(0, 240, 255, 0.5) 1px, transparent 1px)
            `,
                        backgroundSize: "100px 100px",
                    }}
                />
            </div>

            {/* Content */}
            <motion.div
                style={{ scale, opacity }}
                className="relative z-10 container-custom text-center"
            >
                {/* Badge */}
                <motion.div
                    initial={{ opacity: 0, y: 20 }}
                    whileInView={{ opacity: 1, y: 0 }}
                    viewport={{ once: true }}
                    className="inline-flex items-center gap-2 px-6 py-3 rounded-full glass mb-8"
                >
                    <Sparkles className="w-5 h-5 text-[#00F0FF]" />
                    <span className="text-white/80">Ready to Transform Your Business?</span>
                </motion.div>

                {/* Headline */}
                <motion.h2
                    initial={{ opacity: 0, y: 30 }}
                    whileInView={{ opacity: 1, y: 0 }}
                    viewport={{ once: true }}
                    transition={{ delay: 0.1 }}
                    className="text-4xl sm:text-5xl md:text-6xl lg:text-7xl font-bold mb-6 leading-tight"
                >
                    Let's Build the
                    <br />
                    <span className="text-gradient">Future Together</span>
                </motion.h2>

                {/* Description */}
                <motion.p
                    initial={{ opacity: 0, y: 30 }}
                    whileInView={{ opacity: 1, y: 0 }}
                    viewport={{ once: true }}
                    transition={{ delay: 0.2 }}
                    className="text-lg sm:text-xl text-white/60 max-w-2xl mx-auto mb-12"
                >
                    Start your digital transformation journey today. Our team of experts
                    is ready to turn your vision into reality.
                </motion.p>

                {/* CTA Buttons */}
                <motion.div
                    initial={{ opacity: 0, y: 30 }}
                    whileInView={{ opacity: 1, y: 0 }}
                    viewport={{ once: true }}
                    transition={{ delay: 0.3 }}
                    className="flex flex-col sm:flex-row items-center justify-center gap-4"
                >
                    <Link href="/contact">
                        <motion.button
                            className="group relative px-10 py-5 bg-gradient-to-r from-[#00F0FF] to-[#00C4D4] text-black font-bold rounded-full overflow-hidden text-lg"
                            whileHover={{ scale: 1.05, boxShadow: "0 0 60px rgba(0, 240, 255, 0.5)" }}
                            whileTap={{ scale: 0.95 }}
                        >
                            <span className="relative z-10 flex items-center gap-3">
                                Start Your Project
                                <ArrowRight className="w-5 h-5 group-hover:translate-x-1 transition-transform" />
                            </span>
                            <motion.div
                                className="absolute inset-0 bg-gradient-to-r from-[#FF00FF] to-[#D400D4]"
                                initial={{ x: "-100%" }}
                                whileHover={{ x: 0 }}
                                transition={{ duration: 0.4 }}
                            />
                        </motion.button>
                    </Link>

                    <Link href="/case-studies">
                        <motion.button
                            className="px-10 py-5 border border-white/20 text-white font-medium rounded-full hover:border-[#FF00FF]/50 hover:bg-[#FF00FF]/10 transition-all duration-300 text-lg"
                            whileHover={{ scale: 1.05 }}
                            whileTap={{ scale: 0.95 }}
                        >
                            View Our Work
                        </motion.button>
                    </Link>
                </motion.div>

                {/* Trust Indicators */}
                <motion.div
                    initial={{ opacity: 0, y: 30 }}
                    whileInView={{ opacity: 1, y: 0 }}
                    viewport={{ once: true }}
                    transition={{ delay: 0.4 }}
                    className="mt-16 flex flex-wrap items-center justify-center gap-8 text-white/40 text-sm"
                >
                    <span className="flex items-center gap-2">
                        <span className="w-2 h-2 rounded-full bg-green-400" />
                        Free Consultation
                    </span>
                    <span className="flex items-center gap-2">
                        <span className="w-2 h-2 rounded-full bg-green-400" />
                        24/7 Support
                    </span>
                    <span className="flex items-center gap-2">
                        <span className="w-2 h-2 rounded-full bg-green-400" />
                        Quick Response
                    </span>
                </motion.div>
            </motion.div>
        </section>
    );
}
