"use client";

import Link from "next/link";
import { motion } from "framer-motion";
import { Twitter, Linkedin, Github, Dribbble, Mail, MapPin, Phone } from "lucide-react";
import { siteConfig, navigation } from "@/lib/siteConfig";

const footerLinks = {
    company: [
        { name: "About Us", href: "/about" },
        { name: "Careers", href: "/careers" },
        { name: "Press Kit", href: "/press" },
        { name: "Contact", href: "/contact" },
    ],
    resources: [
        { name: "Blog", href: "/blog" },
        { name: "Case Studies", href: "/case-studies" },
        { name: "Documentation", href: "/docs" },
        { name: "Help Center", href: "/help" },
    ],
    legal: [
        { name: "Privacy Policy", href: "/privacy" },
        { name: "Terms of Service", href: "/terms" },
        { name: "Cookie Policy", href: "/cookies" },
    ],
};

const socialLinks = [
    { name: "Twitter", icon: Twitter, href: siteConfig.links.twitter },
    { name: "LinkedIn", icon: Linkedin, href: siteConfig.links.linkedin },
    { name: "GitHub", icon: Github, href: siteConfig.links.github },
    { name: "Dribbble", icon: Dribbble, href: "https://dribbble.com/novaforgelabs" },
];

export default function Footer() {
    return (
        <footer className="relative bg-[#03070A] border-t border-white/5">
            {/* Gradient Top Border */}
            <div className="absolute top-0 left-0 right-0 h-px bg-gradient-to-r from-transparent via-[#00F0FF]/50 to-transparent" />

            <div className="container-custom py-20">
                {/* Main Footer Content */}
                <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-12 gap-12 mb-16">
                    {/* Brand Column */}
                    <div className="lg:col-span-4">
                        <Link href="/" className="inline-block mb-6">
                            <div className="flex items-center gap-3">
                                <div className="w-10 h-10 rounded-lg bg-gradient-to-br from-[#00F0FF] to-[#FF00FF] flex items-center justify-center">
                                    <span className="text-black font-bold text-xl">N</span>
                                </div>
                                <span className="text-xl font-bold tracking-tight">
                                    NovaForge
                                    <span className="text-[#00F0FF]">.</span>
                                </span>
                            </div>
                        </Link>
                        <p className="text-white/60 mb-6 max-w-sm leading-relaxed">
                            {siteConfig.description}
                        </p>

                        {/* Contact Info */}
                        <div className="space-y-3">
                            <a
                                href={`mailto:${siteConfig.contact.email}`}
                                className="flex items-center gap-3 text-white/60 hover:text-[#00F0FF] transition-colors"
                            >
                                <Mail className="w-4 h-4" />
                                <span className="text-sm">{siteConfig.contact.email}</span>
                            </a>
                            <a
                                href={`tel:${siteConfig.contact.phone}`}
                                className="flex items-center gap-3 text-white/60 hover:text-[#00F0FF] transition-colors"
                            >
                                <Phone className="w-4 h-4" />
                                <span className="text-sm">{siteConfig.contact.phone}</span>
                            </a>
                            <div className="flex items-center gap-3 text-white/60">
                                <MapPin className="w-4 h-4" />
                                <span className="text-sm">{siteConfig.contact.address}</span>
                            </div>
                        </div>
                    </div>

                    {/* Links Columns */}
                    <div className="lg:col-span-2">
                        <h4 className="text-white font-semibold mb-4">Company</h4>
                        <ul className="space-y-3">
                            {footerLinks.company.map((link) => (
                                <li key={link.name}>
                                    <Link
                                        href={link.href}
                                        className="text-white/60 hover:text-[#00F0FF] transition-colors text-sm"
                                    >
                                        {link.name}
                                    </Link>
                                </li>
                            ))}
                        </ul>
                    </div>

                    <div className="lg:col-span-2">
                        <h4 className="text-white font-semibold mb-4">Services</h4>
                        <ul className="space-y-3">
                            {navigation.services.slice(0, 4).map((service) => (
                                <li key={service.slug}>
                                    <Link
                                        href={`/services/${service.slug}`}
                                        className="text-white/60 hover:text-[#00F0FF] transition-colors text-sm"
                                    >
                                        {service.name}
                                    </Link>
                                </li>
                            ))}
                        </ul>
                    </div>

                    <div className="lg:col-span-2">
                        <h4 className="text-white font-semibold mb-4">Resources</h4>
                        <ul className="space-y-3">
                            {footerLinks.resources.map((link) => (
                                <li key={link.name}>
                                    <Link
                                        href={link.href}
                                        className="text-white/60 hover:text-[#00F0FF] transition-colors text-sm"
                                    >
                                        {link.name}
                                    </Link>
                                </li>
                            ))}
                        </ul>
                    </div>

                    {/* Newsletter */}
                    <div className="lg:col-span-2">
                        <h4 className="text-white font-semibold mb-4">Stay Updated</h4>
                        <p className="text-white/60 text-sm mb-4">
                            Subscribe to our newsletter for the latest insights.
                        </p>
                        <form className="flex flex-col gap-3">
                            <input
                                type="email"
                                placeholder="Enter your email"
                                className="w-full px-4 py-3 bg-white/5 border border-white/10 rounded-lg text-sm focus:outline-none focus:border-[#00F0FF]/50 transition-colors"
                            />
                            <motion.button
                                type="submit"
                                className="w-full px-4 py-3 bg-[#00F0FF] text-black font-medium rounded-lg hover:bg-[#00F0FF]/90 transition-colors"
                                whileHover={{ scale: 1.02 }}
                                whileTap={{ scale: 0.98 }}
                            >
                                Subscribe
                            </motion.button>
                        </form>
                    </div>
                </div>

                {/* Divider */}
                <div className="h-px bg-white/10 mb-8" />

                {/* Bottom Row */}
                <div className="flex flex-col md:flex-row items-center justify-between gap-6">
                    {/* Copyright */}
                    <p className="text-white/40 text-sm">
                        &copy; {new Date().getFullYear()} {siteConfig.name}. All rights reserved.
                    </p>

                    {/* Social Links */}
                    <div className="flex items-center gap-4">
                        {socialLinks.map((social) => (
                            <a
                                key={social.name}
                                href={social.href}
                                target="_blank"
                                rel="noopener noreferrer"
                                className="w-10 h-10 rounded-full border border-white/10 flex items-center justify-center text-white/60 hover:text-[#00F0FF] hover:border-[#00F0FF]/50 transition-all"
                                aria-label={social.name}
                            >
                                <social.icon className="w-4 h-4" />
                            </a>
                        ))}
                    </div>

                    {/* Legal Links */}
                    <div className="flex items-center gap-6">
                        {footerLinks.legal.map((link) => (
                            <Link
                                key={link.name}
                                href={link.href}
                                className="text-white/40 hover:text-white/80 text-sm transition-colors"
                            >
                                {link.name}
                            </Link>
                        ))}
                    </div>
                </div>
            </div>
        </footer>
    );
}
